Here's an updated `BaseRepository` class that allows you to find by a dynamic field. This example uses C# and Entity Framework Core.

```csharp
public abstract class BaseRepository<T> : IRepository<T> where T : class
{
    private readonly DbContext _context;
    private readonly DbSet<T> _dbSet;

    protected BaseRepository(DbContext context)
    {
        _context = context;
        _dbSet = _context.Set<T>();
    }

    public virtual async Task<T> FindAsync(object id)
    {
        return await _dbSet.FindAsync(id);
    }

    public virtual async Task<T> FindByDynamicFieldAsync(string fieldName, object fieldValue)
    {
        var propertyInfo = typeof(T).GetProperty(fieldName);
        if (propertyInfo == null)
        {
            throw new ArgumentException($"Property {fieldName} does not exist in {typeof(T).Name}");
        }

        var parameter = Expression.Parameter(typeof(T));
        var memberExpression = Expression.MakeMemberAccess(parameter, propertyInfo);
        var constantExpression = Expression.Constant(fieldValue);
        var body = Expression.Equal(memberExpression, constantExpression);
        var lambda = Expression.Lambda<Func<T, bool>>(body, parameter);

        return await _dbSet.FirstOrDefaultAsync(lambda);
    }

